parameters.jsCode:
const json = $json;
// Para incidencias, usamos preferentemente la fecha visible en la web
let baseDate = new Date(json.shipping_status_datetime);

const now = new Date();
let count = 0;
if (baseDate instanceof Date && !isNaN(baseDate.getTime()) && baseDate < now) {
    let cur = new Date(baseDate);
    while (cur < now) {
        // Solo sumamos horas en días laborables (L-V)
        if (cur.getDay() !== 0 && cur.getDay() !== 6) count++;
        cur.setHours(cur.getHours() + 1);
    }
}

return {
    ...json,
    hours_in_status: count
};

